-- ----------------------------------------------------------------------------- Extension-- ---------------------------------------------------------------------------CREATE EXTENSION IF NOT EXISTS pgcrypto;-- ----------------------------------------------------------------------------- users-- Core identity table. Passwords are bcrypt-hashed; raw values are never stored.-- Soft-delete pattern: deleted_at IS NOT NULL means the account is deactivated.-- ---------------------------------------------------------------------------CREATE TABLE IF NOT EXISTS users (    id                   UUID         PRIMARY KEY,    first_name           VARCHAR(100),    last_name            VARCHAR(100),    username             VARCHAR(50)  NOT NULL,    password             VARCHAR(255) NOT NULL,    role                 VARCHAR(20)  NOT NULL DEFAULT 'USER',    email                VARCHAR(255),    phone_number         VARCHAR(30),    email_verified       BOOLEAN      NOT NULL DEFAULT FALSE,    email_verified_at    TIMESTAMPTZ,    is_active            BOOLEAN      NOT NULL DEFAULT TRUE,    created_at           TIMESTAMPTZ  NOT NULL DEFAULT NOW(),    last_login_at        TIMESTAMPTZ,    password_updated_at  TIMESTAMPTZ,    failed_login_attempts INT4        NOT NULL DEFAULT 0,    locked_until         TIMESTAMPTZ,    deleted_at           TIMESTAMPTZ,    CONSTRAINT users_email_key    UNIQUE (email),    CONSTRAINT users_username_key UNIQUE (username));-- ----------------------------------------------------------------------------- refresh_tokens-- Short-lived rolling refresh tokens. Raw token is never persisted; only a-- SHA-256 hash is stored so a leaked DB dump cannot replay sessions.-- ---------------------------------------------------------------------------CREATE TABLE IF NOT EXISTS refresh_tokens (    id          UUID         PRIMARY KEY DEFAULT gen_random_uuid(),    user_id     UUID         NOT NULL REFERENCES users(id) ON DELETE CASCADE,    token_hash  VARCHAR(255) NOT NULL UNIQUE,    device_hint VARCHAR(255),    issued_at   TIMESTAMPTZ  NOT NULL DEFAULT NOW(),    expires_at  TIMESTAMPTZ  NOT NULL,    revoked_at  TIMESTAMPTZ);CREATE INDEX IF NOT EXISTS idx_refresh_tokens_user ON refresh_tokens (user_id);-- ----------------------------------------------------------------------------- upload_sessions-- Tracks resumable chunked-upload state for large file transfers.-- received_chunks is a PostgreSQL integer array; the server uses it to detect-- missing chunks and allow out-of-order submission.-- expires_at defaults to 48 hours; a background job purges stale rows.-- ---------------------------------------------------------------------------CREATE TABLE IF NOT EXISTS upload_sessions (    id               UUID         PRIMARY KEY DEFAULT gen_random_uuid(),    user_id          UUID         NOT NULL REFERENCES users(id),    filename         VARCHAR(512) NOT NULL,    total_size       BIGINT       NOT NULL,    chunk_size       INT          NOT NULL,    total_chunks     INT          NOT NULL,    received_chunks  INT[]        NOT NULL DEFAULT '{}',    destination_path TEXT         NOT NULL,    status           VARCHAR(20)  NOT NULL DEFAULT 'PENDING',    created_at       TIMESTAMPTZ  NOT NULL DEFAULT NOW(),    expires_at       TIMESTAMPTZ  NOT NULL DEFAULT NOW() + INTERVAL '48 hours');-- ----------------------------------------------------------------------------- transfer_log-- Immutable audit record for every file transfer (upload / download / move).-- avg_speed_bps and duration_ms are populated on completion.-- ---------------------------------------------------------------------------CREATE TABLE IF NOT EXISTS transfer_log (    id            UUID         PRIMARY KEY DEFAULT gen_random_uuid(),    user_id       UUID         REFERENCES users(id),    filename      VARCHAR(512) NOT NULL,    source        VARCHAR(512),    destination   VARCHAR(512),    size_bytes    BIGINT,    avg_speed_bps BIGINT,    duration_ms   BIGINT,    status        VARCHAR(20)  NOT NULL DEFAULT 'PENDING',    error_message TEXT,    created_at    TIMESTAMPTZ  NOT NULL DEFAULT NOW());CREATE INDEX IF NOT EXISTS idx_transfer_log_user ON transfer_log (user_id, created_at DESC);-- ----------------------------------------------------------------------------- otp_tokens-- Single-use tokens for password-reset and device-pairing flows.-- purpose distinguishes use-cases: 'RESET' | 'PAIR'.-- used_at IS NOT NULL means the token has been consumed.-- ---------------------------------------------------------------------------CREATE TABLE IF NOT EXISTS otp_tokens (    id         UUID         PRIMARY KEY DEFAULT gen_random_uuid(),    user_id    UUID         NOT NULL REFERENCES users(id),    token_hash VARCHAR(255) NOT NULL,    purpose    VARCHAR(30)  NOT NULL,    expires_at TIMESTAMPTZ  NOT NULL,    used_at    TIMESTAMPTZ);-- ----------------------------------------------------------------------------- Enum types-- DO-EXCEPTION blocks make these idempotent; Flyway checksums the file, so-- re-running manually against an existing database is safe.-- ---------------------------------------------------------------------------DO $$BEGIN    CREATE TYPE auth_type_enum AS ENUM (        'password',        'key',        'key_passphrase'    );EXCEPTION    WHEN duplicate_object THEN NULL;END $$;DO $$BEGIN    CREATE TYPE protocol_type_enum AS ENUM (        'ssh_sftp',        'ftp',        's3',        'azure_blob',        'gcs'    );EXCEPTION    WHEN duplicate_object THEN NULL;END $$;-- ----------------------------------------------------------------------------- saved_hosts-- User-defined remote host profiles. Credentials are AES-256-GCM encrypted-- at the application layer before storage; the DB never holds plaintext keys.-- workspace_preference drives the sidebar and landing view on reconnect.-- ---------------------------------------------------------------------------CREATE TABLE IF NOT EXISTS saved_hosts (    id                       UUID               PRIMARY KEY,    user_id                  UUID               NOT NULL,    label                    VARCHAR(100),    protocol_type            protocol_type_enum NOT NULL DEFAULT 'ssh_sftp',    hostname                 VARCHAR(255),    port                     INTEGER            DEFAULT 22,    username                 VARCHAR(100),    auth_type                auth_type_enum,    encrypted_password       TEXT,    encrypted_privatekey     TEXT,    encrypted_passphrase     TEXT,    created_at               TIMESTAMP,    last_used                TIMESTAMP,    strict_host_key_checking BOOLEAN            NOT NULL DEFAULT FALSE,    expected_fingerprint     TEXT,    workspace_preference     VARCHAR(20)        DEFAULT 'ssh');-- ----------------------------------------------------------------------------- session_log-- Lightweight audit record for every remote session opened by a user.-- Persists across server restarts and session expiry, providing a full-- connection history with OS/service details.-- id is a UUID v7 (time-ordered) generated by the application layer.-- ---------------------------------------------------------------------------CREATE TABLE IF NOT EXISTS session_log (    id         UUID         PRIMARY KEY,    user_id    UUID         NOT NULL REFERENCES users(id),    label      VARCHAR(200),    protocol   VARCHAR(30)  NOT NULL,    host       VARCHAR(255) NOT NULL,    port       INTEGER      NOT NULL,    username   VARCHAR(100),    remote_os  VARCHAR(255),    created_at TIMESTAMPTZ  NOT NULL DEFAULT NOW(),    closed_at  TIMESTAMPTZ);CREATE INDEX IF NOT EXISTS idx_session_log_user ON session_log (user_id, created_at DESC);-- ----------------------------------------------------------------------------- session_analytics_snapshot-- Time-series analytics probes captured per active session.-- Scalar metric columns allow efficient range queries and aggregations.-- snapshot_json stores the full payload (traffic history, connected nodes)-- for replay without re-querying individual metric columns.-- ---------------------------------------------------------------------------CREATE TABLE IF NOT EXISTS session_analytics_snapshot (    id                       UUID             PRIMARY KEY DEFAULT gen_random_uuid(),    session_id               UUID             NOT NULL,    user_id                  UUID             NOT NULL REFERENCES users(id),    host                     VARCHAR(255),    state                    VARCHAR(30),    captured_at              TIMESTAMPTZ      NOT NULL DEFAULT NOW(),    session_duration_seconds BIGINT,    latency_avg_ms           DOUBLE PRECISION,    latency_min_ms           DOUBLE PRECISION,    latency_max_ms           DOUBLE PRECISION,    packet_loss_percent      DOUBLE PRECISION,    packets_sent             INTEGER,    packets_received         INTEGER,    current_upload_bps       BIGINT,    current_download_bps     BIGINT,    total_uploaded_bytes     BIGINT,    total_downloaded_bytes   BIGINT,    cpu_percent              DOUBLE PRECISION,    memory_used_percent      DOUBLE PRECISION,    memory_used_bytes        BIGINT,    memory_total_bytes       BIGINT,    disk_used_percent        DOUBLE PRECISION,    disk_used_bytes          BIGINT,    disk_total_bytes         BIGINT,    ssh_cipher               VARCHAR(100),    region                   VARCHAR(100),    remote_pid               BIGINT,    snapshot_json            JSONB            NOT NULL);CREATE INDEX IF NOT EXISTS idx_analytics_snapshot_session  ON session_analytics_snapshot (session_id,  captured_at DESC);CREATE INDEX IF NOT EXISTS idx_analytics_snapshot_user     ON session_analytics_snapshot (user_id,     captured_at DESC);CREATE INDEX IF NOT EXISTS idx_analytics_snapshot_captured ON session_analytics_snapshot (captured_at  DESC);